;  霧の島

name = 霧の島・地上
insideName = Island of Mist
level = 28
bgm = forest
external = w:4, s:4
isOutdoor = true
shadow = light
sky = mistysea
blank = rock
effect = BE_fog

; 画像パーツ
━ = rockw
　 = sand
〰 = sea
❖ = sand
／ = doorw
☗ = downstair
⑴ = bulletin

; 敵情報
maxGroups = 2
monsters = 砂ぐも,海ヘビ,ハーピー,シャドウ,パイレーツ,ブレイズマン

; 移動ポイント
(A) = map:霧の島の洞窟Ｂ１, x:9, y:10, way:e, symbol:cave, ask:Go to the dungeon?
(B) = map:霧の島の洞窟Ｂ１, x:10, y:0, way:w, symbol:cave, ask:Go to the dungeon?
(C) = map:霧の島の洞窟Ｂ１, x:5, y:3, way:n, symbol:cave, ask:Go to the dungeon?
(D) = map:海岸, x:3, y:0, way:n, symbol:movev, ask:Go to the next map?
(E) = map:海岸, x:4, y:0, way:n, symbol:movev, ask:Go to the next map?
(F) = map:海岸, x:5, y:0, way:n, symbol:movev, ask:Go to the next map?

; 宝箱
box[1] = 沈黙の杖_u,イレースマジックの魔法書_u,トライデント_u,ボム,アウラの宝珠,武芸の秘薬

