;◆イベント◆

; 初期発生イベント
events = [1, 2]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@roadguide n=Coast s="Swaros Store"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] true

@shop name=スワロスの店
@walk turn=e move=e
[texton]
[name n=Swaros f=waroth_01]「Please come again.」[k]
[textoff]

; クエストを受領していたらイベント４を追加
@addevent name=スワロスの店 num=4 cond='o.パンツコレクション.accepted && ! o.パンツコレクション.completed'

[eventoff]
